Here's a complete example:

**XAML:**
```xml
<RefreshView IsRefreshing="{Binding IsRefreshing}"
             Command="{Binding RefreshCommand}">
    <CollectionView ItemsSource="{Binding Items}"
                    SelectionMode="Single"
                    SelectedItem="{Binding SelectedItem}"
                    SelectionChangedCommand="{Binding SelectionChangedCommand}">
        <CollectionView.ItemTemplate>
            <DataTemplate x:DataType="models:Item">
                <VerticalStackLayout Padding="10">
                    <Label Text="{Binding Name}" FontSize="18" />
                    <Label Text="{Binding Description}" FontSize="14"
                           TextColor="Gray" />
                </VerticalStackLayout>
            </DataTemplate>
        </CollectionView.ItemTemplate>
    </CollectionView>
</RefreshView>
```

**ViewModel:**
```csharp
public partial class ItemsViewModel : ObservableObject
{
    private readonly IApiService _api;
    private readonly INavigationService _nav;

    [ObservableProperty]
    private bool _isRefreshing;

    [ObservableProperty]
    private Item? _selectedItem;

    public ObservableCollection<Item> Items { get; } = new();

    public ItemsViewModel(IApiService api, INavigationService nav)
    {
        _api = api;
        _nav = nav;
    }

    [RelayCommand]
    private async Task RefreshAsync()
    {
        try
        {
            var data = await _api.GetItemsAsync();
            Items.Clear();
            foreach (var item in data)
                Items.Add(item);
        }
        finally
        {
            IsRefreshing = false;  // stops the spinner
        }
    }

    [RelayCommand]
    private async Task SelectionChangedAsync()
    {
        if (SelectedItem is null) return;

        await _nav.GoToAsync(nameof(DetailPage),
            new Dictionary<string, object> { ["Item"] = SelectedItem });

        SelectedItem = null;  // reset so the same item can be re-selected
    }
}
```

**Key binding points:**

| XAML Property | ViewModel Member | Purpose |
|---|---|---|
| `IsRefreshing` | `IsRefreshing` (bool) | Two-way — set `false` to dismiss spinner |
| `Command` | `RefreshCommand` | Triggered on pull-down gesture |
| `ItemsSource` | `Items` (ObservableCollection) | Data source |
| `SelectedItem` | `SelectedItem` | Two-way — holds current selection |
| `SelectionChangedCommand` | `SelectionChangedCommand` | Fires on tap; navigates to detail |

**Important details:**
- Set `IsRefreshing = false` in a `finally` block so the spinner always stops, even on errors.
- Reset `SelectedItem = null` after navigation so the user can tap the same row again.
- Uses **CommunityToolkit.Mvvm** source generators (`[ObservableProperty]`, `[RelayCommand]`) to eliminate boilerplate.
